using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with a default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable → succeeds
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not found");

// Now use options that only know about a fixed set of types (no Person).
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            ti =>
            {
                // Reject everything except string
                if (ti.Type != typeof(string))
                    throw new NotSupportedException($"Type {ti.Type} not supported");
            }
        }
    }
};

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
    Console.WriteLine($"TryGetTypeInfo<Person> on limited → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on limited → not found (no exception thrown)");

public record Person(string Name, int Age);

